import { useEffect, useRef, useState } from 'react';
import { AUTH_ACCESS_TOKEN_KEY, AUTH_USER_STORAGE_KEY } from '@linm-soft-org/linm-web-common-components';
import { clearMfeListFilterSessions, MFE_LIST_FILTER_NS } from '../utils/listFilterSession';
import { readListFilterAuthScopeFromStorage } from '../utils/listFilterAuthScope';

/**
 * Clear all list-filter session keys when user/company changes or on platform logout.
 */
export function useListFilterSessionGuard(): void {
  const [auth, setAuth] = useState(readListFilterAuthScopeFromStorage);
  const prevAuthRef = useRef<string | null>(null);

  useEffect(() => {
    const sync = () => setAuth(readListFilterAuthScopeFromStorage());
    window.addEventListener('storage', sync);
    window.addEventListener('linm:auth:logout', sync);
    window.addEventListener('linm:auth:token-changed', sync);
    window.addEventListener('linm:auth:changed', sync);
    window.addEventListener('linm:company:changed', sync);
    return () => {
      window.removeEventListener('storage', sync);
      window.removeEventListener('linm:auth:logout', sync);
      window.removeEventListener('linm:auth:token-changed', sync);
      window.removeEventListener('linm:auth:changed', sync);
      window.removeEventListener('linm:company:changed', sync);
    };
  }, []);

  useEffect(() => {
    if (prevAuthRef.current !== null && prevAuthRef.current !== auth) {
      clearMfeListFilterSessions(MFE_LIST_FILTER_NS);
    }
    prevAuthRef.current = auth;
  }, [auth]);

  useEffect(() => {
    const clear = () => clearMfeListFilterSessions(MFE_LIST_FILTER_NS);

    window.addEventListener('linm:auth:logout', clear);

    const onStorage = (e: StorageEvent) => {
      if (
        (e.key === AUTH_USER_STORAGE_KEY && !e.newValue)
        || (e.key === AUTH_ACCESS_TOKEN_KEY && !e.newValue)
      ) {
        clear();
      }
    };
    window.addEventListener('storage', onStorage);

    return () => {
      window.removeEventListener('linm:auth:logout', clear);
      window.removeEventListener('storage', onStorage);
    };
  }, []);
}
